import React from "react";

export default function HourlyItem({ label, temp, pop, icon, desc }) {
  const iconUrl = `https://openweathermap.org/img/wn/${icon}.png`;

  return (
    <div className="snap-start shrink-0 w-20 bg-black/35 backdrop-blur-md border border-white/10 rounded-xl shadow-md py-3 px-2 text-center">
      <div className="text-[11px] text-white/70 font-medium">{label}</div>
      <img
        src={iconUrl}
        alt={desc}
        className="w-10 h-10 mx-auto my-1 drop-shadow-[0_6px_22px_rgba(128,90,213,0.35)]"
      />
      <div className="text-white text-base font-semibold">{temp}°</div>
      {typeof pop === "number" && (
        <div className="text-[11px] text-white/60 mt-1">
          {pop}% rain
        </div>
      )}
    </div>
  );
}
